mapper.update:
update tz_category
category_name = #{categoryName}, category_code = #{categoryCode}, sort_num = #{sortNum}, status = #{status}, description = #{description}, update_by = #{updateBy}, remark = #{remark}, update_time = sysdate()
where category_id = #{categoryId}

update tz_user_profile p inner join sys_user u on u.user_id = p.user_id
u.nick_name = #{nickName}, u.email = #{email}, u.phonenumber = #{phonenumber}, p.college = #{college}, p.grade = #{grade}, p.major = #{major}, p.introduction = #{introduction}, p.update_time = sysdate()
where p.user_id = #{userId}

mapper.select:
select ,
if(f.question_id is null, 'N', 'Y') as favorited
'N' as favorited
from tz_question q left join tz_category c on c.category_id = q.category_id left join sys_user u on u.user_id = q.user_id
left join tz_question_favorite f on f.question_id = q.question_id and f.user_id = #{userId}
where q.del_flag = '0' and q.status = '1' order by q.answer_count desc, q.view_count desc, q.create_time desc limit #{limit}

mapper.update:
update tz_question
category_id = #{categoryId}, title = #{title}, content = #{content}, status = #{status}, reject_reason = #{rejectReason}, is_anonymous = #{isAnonymous}, view_count = #{viewCount}, answer_count = #{answerCount}, favorite_count = #{favoriteCount}, update_by = #{updateBy}, update_time = sysdate()
where question_id = #{questionId}

mapper.select:
select q.question_id, q.category_id, q.user_id, q.title, q.content, q.status, q.reject_reason, q.is_anonymous, q.view_count, q.answer_count, q.favorite_count, q.create_by, q.create_time, q.update_by, q.update_time, c.category_name, u.user_name as publisher_name, u.nick_name as publisher_nick_name from tz_question q left join tz_category c on c.category_id = q.category_id left join sys_user u on u.user_id = q.user_id where q.del_flag = '0'
and q.category_id = #{categoryId}
and q.status = #{status}
and (q.title like concat('%', #{keyword}, '%') or q.content like concat('%', #{keyword}, '%'))
order by q.create_time desc

mapper.update:
update tz_answer
content = #{content}, status = #{status}, reject_reason = #{rejectReason}, is_anonymous = #{isAnonymous}, like_count = #{likeCount}, update_by = #{updateBy}, update_time = sysdate()
where answer_id = #{answerId}

mapper.select:
select a.answer_id, a.question_id, a.user_id, a.content, a.status, a.reject_reason, a.is_anonymous, a.like_count, a.create_by, a.create_time, a.update_by, a.update_time, q.title as question_title, u.user_name as publisher_name, u.nick_name as publisher_nick_name from tz_answer a left join tz_question q on q.question_id = a.question_id left join sys_user u on u.user_id = a.user_id where a.del_flag = '0'
and a.question_id = #{questionId}
and a.status = #{status}
and a.content like concat('%', #{content}, '%')
order by a.create_time desc

mapper.update:
update tz_question
set answer_count = (
    select count(1)
    from (
        select answer_id
        from tz_answer
        where question_id = #{questionId} and del_flag = '0' and status = '1'
    ) t
)
where question_id = #{questionId}

update tz_question
set favorite_count = (
    select count(1)
    from (
        select question_id
        from tz_question_favorite
        where question_id = #{questionId}
    ) t
)
where question_id = #{questionId}
